{{(() => {
  const selected = appsmith.store.botConfigSelected || {};
  const currentValue = selected.fallback_team_id ? String(selected.fallback_team_id) : "";
  const currentLabel = selected.fallback_team_id
    ? `${selected.fallback_team_name || "Time fallback"} (#${selected.fallback_team_id})`
    : null;

  const emptyOption = [{ label: "Sem time fallback", value: "" }];
  const currentOption = currentValue ? [{ label: currentLabel, value: currentValue }] : [];

  const dbOptions = (ListChatwootTeams.data || [])
    .map((r) => ({ label: String(r.label), value: String(r.value) }))
    .filter((o) => !currentValue || o.value !== currentValue);

  return emptyOption.concat(currentOption).concat(dbOptions);
})()}}
